// Obtém o primeiro item do fluxo
const item = $input.first();

// Garante que há dados na entrada
if (!item || !item.json || !item.json.text) {
  throw new Error("A chave 'text' não foi encontrada no JSON de entrada.");
}

// Processa o texto removendo todas as quebras de linha, emojis e caracteres especiais
const textoEntrada = item.json.text; // Usa a chave correta para pegar o texto de entrada

// Remove quebras de linha (\n)
let textoProcessado = textoEntrada.replace(/\n/g, "");

// Remove emojis
textoProcessado = textoProcessado.replace(
  /[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F700}-\u{1F77F}]|[\u{1F780}-\u{1F7FF}]|[\u{1F800}-\u{1F8FF}]|[\u{1F900}-\u{1F9FF}]|[\u{1FA00}-\u{1FA6F}]|[\u{1FA70}-\u{1FAFF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]|[\u{FE00}-\u{FE0F}]|[\u{1F1E0}-\u{1F1FF}]/gu,
  ""
);

// Remove caracteres especiais, mantendo apenas letras, números e espaços
textoProcessado = textoProcessado.replace(/[^a-zA-Z0-9À-ÿ\s,\.\?\!\:]/g, "");

// Retorna o resultado
return {
  textoOriginal: textoEntrada,
  textoSemQuebrasNemEmojisNemEspeciais: textoProcessado,
};

// 1. Ordena as mensagens por data (mais recente → mais antiga)
items.sort((a, b) => new Date(b.json.created_at) - new Date(a.json.created_at));

// 2. Pega apenas as últimas 50 mensagens caso o histórico seja muito longo
const itensRecentes = items.slice(-10);

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, '0');
  const mes = String(d.getMonth() + 1).padStart(2, '0');
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of itensRecentes) {
  const row = item.json;
  const dataFormatada = formatarData(row.created_at);

  // Processa mensagem do Usuário
  if (row.mensagem_usuario && row.mensagem_usuario.toString().trim() !== "") {
    historico.push(`${dataFormatada} - Usuário: ${row.mensagem_usuario.toString().trim()}`);
  }

  // Processa mensagem do Agente
  if (row.mensagem_agente && row.mensagem_agente.toString().trim() !== "") {
    // Caso a mensagem do agente venha como array/objeto de outro fluxo, converte para string
    const msgAgente = typeof row.mensagem_agente === 'string' 
      ? row.mensagem_agente 
      : JSON.stringify(row.mensagem_agente);

    historico.push(`${dataFormatada} - Agente: ${msgAgente.trim()}`);
  }
}

return [
  {
    json: {
      historico_conversa: historico.join("\n\n")
    }
  }
];

